template <const unsigned long long mod,const unsigned long long tmp=(-mod)/mod+1> struct Modint{
	int val;
	Modint()=default;
	template <typename type> Modint(const type &num){ val=barrett(num); }
	int barrett(unsigned long long num){ return ((num-=((__uint128_t)num*tmp>>64)*mod)>=mod?num-mod:num); }
	int inverse(int num){
		int a=0,b=1,x=num,y=mod,t; for(;x;) t=y/x,swap(x,y-=t*x),swap(a-=t*b,b); return (a<0?a+mod:a);
	}
	const int& operator () () const { return val; }
	Modint& operator += (const Modint &rhs){ if((val+=rhs()-mod)<0) val+=mod; return (*this); }
	Modint& operator -= (const Modint &rhs){ if((val-=rhs())<0) val+=mod; return (*this); }
	Modint& operator *= (const Modint &rhs){ val=barrett(1ull*val*rhs()); return (*this); }
	Modint& operator /= (const Modint &rhs){ val=barrett(1ull*val*inverse(rhs())); return (*this); }
	template <typename type> Modint& operator ^= (const type &rhs){
		Modint t=1,a=(*this); for(type b=rhs;b;b>>=1,a*=a) if(b&1) t*=a; return ((*this)=t);
	}
	friend Modint operator + (const Modint &lhs,const Modint &rhs){ return (Modint(lhs)+=rhs); }
	friend Modint operator - (const Modint &lhs,const Modint &rhs){ return (Modint(lhs)-=rhs); }
	friend Modint operator * (const Modint &lhs,const Modint &rhs){ return (Modint(lhs)*=rhs); }
	friend Modint operator / (const Modint &lhs,const Modint &rhs){ return (Modint(lhs)/=rhs); }
	template <typename type> friend Modint operator ^ (const Modint &lhs,const type &rhs){ return (Modint(lhs)^=rhs); }
	Modint operator + () const { return (*this); } Modint operator - () const { return Modint()-val; }
	Modint& operator ++ (){ return (*this)+=1; } Modint operator ++ (int){ Modint res(*this); (*this)+=1; return res; }
	Modint& operator -- (){ return (*this)-=1; } Modint operator -- (int){ Modint res(*this); (*this)-=1; return res; }
	friend bool operator == (const Modint &lhs,const Modint &rhs){ return (lhs()==rhs()); }
	friend bool operator != (const Modint &lhs,const Modint &rhs){ return (lhs()!=rhs()); }
	friend bool operator >= (const Modint &lhs,const Modint &rhs){ return (lhs()>=rhs()); }
	friend bool operator <= (const Modint &lhs,const Modint &rhs){ return (lhs()<=rhs()); }
	friend bool operator > (const Modint &lhs,const Modint &rhs){ return (lhs()>rhs()); }
	friend bool operator < (const Modint &lhs,const Modint &rhs){ return (lhs()<rhs()); }
};
inline int read()
{
    int x=0,f=1;char ch=getchar();
    while(!isdigit(ch)){if(ch=='-') f=-1;ch=getchar();}
    while(isdigit(ch)){x=x*10+ch-'0';ch=getchar();}
    return x*f;
}
inline void write(int x)
{
    if(x<0){putchar('-');x=-x;}
    if(x>9) write(x/10);
    putchar(x%10+'0');
}
