			if(h[j]>h[i])
			{
				dp[i][j][1]+=dp[i][j-1][0];
			}
			if(h[j]>h[j-1])
			{
				dp[i][j][1]+=dp[i][j-1][1];
			}
			dp[i][j][0]*=1;
			dp[i][j][1]*=1;
		}
	}
	cout<<(dp[1][n][0]*1+dp[1][n][1]*1)();
	return 0;
}
